{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting data structures, business workflows, partner integrations, and the meaning of 'delivery completion' itself.",
    "bounded_context": "Shipment / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more destinations. With this change, a Shipment becomes a container for multiple delivery obligations." },
      { "term": "Recipient", "definition": "A party who receives goods from a Shipment. Each Recipient has a name, address, phone number, and now delivery preferences. Recipient becomes a first-class entity rather than an embedded value object." },
      { "term": "Delivery Preference", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time windows, safe-place authorization, signature requirements, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "PROPOSED: The first or default recipient on a multi-recipient shipment. Critical for backward compatibility and for defining who is the 'owner' of the shipment for notifications and billing." },
      { "term": "Shipment Completion", "definition": "Previously: goods delivered to the single recipient. NOW AMBIGUOUS: must be redefined — is a Shipment complete when ALL recipients have received their portion, or when ANY has?" },
      { "term": "Split Delivery", "definition": "The operational act of a courier delivering portions of a single Shipment to multiple addresses, potentially across different routes and time windows." },
      { "term": "Partner Payload", "definition": "The data contract sent to external partner APIs describing a Shipment. Currently assumes a single recipient per shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero recipients is physically meaningless — there is no destination. This is a state integrity constraint: the system cannot route, price, or deliver a shipment without at least one recipient.",
      "testable_assertion": "Any attempt to create or update a Shipment to have zero Recipients must be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically execute a delivery. Without them, the courier cannot locate the destination or contact the recipient. Data consistency constraint.",
      "testable_assertion": "Creating a Recipient with a null or empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a single Shipment must have a unique address.",
      "invariant": false,
      "invariant_justification": "While delivering twice to the same address under one shipment is unusual, there could be legitimate cases (different apartment units at the same building, or different people at the same address). This is a policy decision, not a physical constraint. A VP could allow or disallow it.",
      "testable_assertion": "If enforced: adding a Recipient with a duplicate address to a Shipment raises a validation warning or error. If relaxed: duplicates are permitted."
    },
    {
      "id": "BR-4",
      "rule": "Delivery preferences are owned by each Recipient independently and do not cascade from the Shipment level.",
      "invariant": true,
      "invariant_justification": "The entire point of the model change is per-recipient preferences. If preferences were inherited or shared, the 1:N model adds no value. This is a data integrity constraint — Recipient A's 'signature required' must not leak to Recipient B's 'leave at door'.",
      "testable_assertion": "Updating delivery preferences on Recipient A must not affect Recipient B on the same Shipment."
    },
    {
      "id": "BR-5",
      "rule": "Shipment completion requires successful delivery to ALL Recipients, not just one.",
      "invariant": false,
      "invariant_justification": "This is a business policy, not a physical law. The business could choose partial-completion models, per-recipient status tracking, or all-or-nothing semantics. A VP could change this threshold.",
      "testable_assertion": "A Shipment with 3 Recipients where only 2 have been delivered must NOT have status 'Completed'. It should have status 'Partially Delivered' or equivalent."
    },
    {
      "id": "BR-6",
      "rule": "Each Recipient on a multi-recipient Shipment must have an independent delivery status.",
      "invariant": true,
      "invariant_justification": "If recipients share a single delivery status, the system cannot represent the reality that Recipient A received their goods but Recipient B did not. This is a state integrity issue — the system would be lying about the physical world.",
      "testable_assertion": "Each Recipient entity must carry its own delivery status field (e.g., Pending, Attempted, Delivered, Failed). Updating one Recipient's status must not change another's."
    },
    {
      "id": "BR-7",
      "rule": "Existing single-recipient Shipments must remain valid and fully functional after the model migration.",
      "invariant": true,
      "invariant_justification": "2 million production records cannot be broken by a schema change. This is a data consistency constraint — existing shipments must be queryable, updatable, and deliverable without data loss.",
      "testable_assertion": "After migration, all 2M existing Shipments must have exactly one Recipient with all original data (name, address, phone) preserved. Querying any existing Shipment must return correct data."
    },
    {
      "id": "BR-8",
      "rule": "External partner APIs must continue to receive shipment data in a backward-compatible format until partners have migrated.",
      "invariant": true,
      "invariant_justification": "Breaking partner integrations is a contractual and operational integrity issue. Partners who have not upgraded their systems will fail to process shipments, causing real-world delivery failures.",
      "testable_assertion": "Partner API payloads for single-recipient shipments must be identical to the current format. Multi-recipient shipments must either be flattened to the primary recipient or sent via a versioned endpoint that partners have opted into."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies multiple Recipients, each with name, address, phone, and unique delivery preferences",
      "then": "The Shipment is created with all Recipients persisted, each with their own delivery preferences and an independent delivery status of 'Pending'"
    },
    {
      "id": "AC-2",
      "given": "A Shipment is being created",
      "when": "The creator provides zero Recipients",
      "then": "The system rejects the request with a clear validation error: 'A Shipment must have at least one Recipient'"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment from the legacy data set",
      "when": "The Shipment is queried after migration",
      "then": "It returns with exactly one Recipient containing the original name, address, and phone number, with default delivery preferences applied"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "The Shipment status is queried",
      "then": "The Shipment status is 'Partially Delivered', Recipient A's status is 'Delivered', and Recipient B's status is 'Pending'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "The shipment data is sent to an external partner API that has NOT migrated to the new contract",
      "then": "The partner receives a payload in the legacy single-recipient format using the primary recipient's data, with no breaking changes"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment with 3 Recipients",
      "when": "Delivery preferences are updated for Recipient B (e.g., change to 'Leave at door')",
      "then": "Only Recipient B's preferences are modified; Recipient A and C retain their original preferences unchanged"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with one Recipient",
      "when": "The last Recipient is removed",
      "then": "The system rejects the removal with a validation error enforcing the minimum-one-recipient invariant"
    },
    {
      "id": "AC-8",
      "given": "A courier is assigned to a multi-recipient Shipment",
      "when": "The courier views the delivery details",
      "then": "All Recipients are listed with their individual addresses, contact details, and delivery preferences, enabling the courier to plan a multi-stop route"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment has 50+ Recipients (bulk/corporate distribution)",
      "expected_behavior": "The system should enforce a maximum recipient limit per Shipment (policy-configurable). Beyond the limit, the sender should be guided to create multiple Shipments. Without a cap, routing algorithms, courier UX, and partner payloads could degrade."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "The system must define whether mid-transit recipient addition is allowed. If allowed, the courier must be notified and the route recalculated. If disallowed, the system rejects the addition once the Shipment leaves 'Created' or 'Ready' status."
    },
    {
      "scenario": "All Recipients except one have been delivered, and the last delivery fails permanently",
      "expected_behavior": "The Shipment should move to a terminal state like 'Completed with Exceptions'. The failed Recipient should have status 'Failed' with a reason. The successfully delivered Recipients must not be affected or rolled back."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., Recipient A requires morning delivery, Recipient B requires evening)",
      "expected_behavior": "The system must allow this — preferences are per-recipient, not per-shipment. Route optimization must handle multi-window deliveries. If the preferences make a single-trip delivery impossible, the system should flag this to operations for split routing."
    },
    {
      "scenario": "A partner API webhook fires on 'Shipment Delivered' — but only 2 of 3 Recipients have received goods",
      "expected_behavior": "The webhook must NOT fire until the Shipment reaches its terminal state. New webhook events may be needed: 'Recipient Delivered' for per-recipient tracking, and 'Shipment Completed' only when all recipients are resolved."
    },
    {
      "scenario": "Data migration: a legacy Shipment has recipient data stored as flat columns on the Shipment table, not as a separate entity",
      "expected_behavior": "Migration must extract flat recipient fields into the new Recipient entity/table with a foreign key back to the Shipment. The migration must be idempotent and reversible. Null delivery preferences should be filled with sensible defaults (e.g., 'Standard' delivery)."
    },
    {
      "scenario": "Pricing: a multi-recipient Shipment delivers to 3 different addresses across a city",
      "expected_behavior": "The pricing model must account for multi-stop deliveries. A single-address price cannot apply to 3 addresses. The pricing domain must be notified of this model change — it likely needs its own evolution."
    },
    {
      "scenario": "A Recipient is removed from a multi-recipient Shipment after their portion has already been delivered",
      "expected_behavior": "Removal must be blocked for Recipients with status 'Delivered' — you cannot un-deliver a package. The system should reject with: 'Cannot remove a Recipient whose delivery has been completed.'"
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments enable new revenue streams (bulk delivery, corporate distribution, gift-to-multiple). However, pricing models must be reworked — charging per-shipment no longer makes sense when one shipment serves 5 addresses. Risk of revenue leakage if pricing is not updated simultaneously. Migration costs are non-trivial: data migration of 2M records, partner API versioning, and QA across all touchpoints.",
    "operational": "Significant operational complexity increase. Courier routing changes from single-destination to multi-stop optimization. Dispatch logic must account for split deliveries. Shipment status tracking becomes a state machine with partial-completion states. Operations dashboards, reporting, and SLA tracking all need updates to handle the new cardinality.",
    "user": "Senders gain flexibility — one shipment to multiple people. Couriers face increased complexity per shipment. Recipients experience no change for single-recipient shipments. For multi-recipient shipments, notification and tracking UX must be per-recipient (each recipient should only see their own delivery status, not others').",
    "risk": "HIGH. This is a foundational model change. Risks include: (1) Data migration failure corrupting 2M shipments, (2) Partner API breakage causing delivery failures, (3) Incomplete status tracking leading to lost deliveries, (4) Pricing gaps causing revenue loss, (5) Courier confusion with new multi-stop workflows. Phased rollout strongly recommended.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability. Must learn new UI. Existing single-recipient workflows must remain identical." },
      { "group": "Recipients", "impact": "Minimal direct impact. Must receive per-recipient tracking and notifications, not shipment-level. Privacy concern: Recipient A should not see Recipient B's address or details." },
      { "group": "Couriers/Drivers", "impact": "Major workflow change. Multi-stop routing, per-recipient status updates, handling partial delivery scenarios. Training and app UI updates required." },
      { "group": "External Partners", "impact": "API contract change. Must be given migration timeline, versioned endpoints, and backward-compatible payloads during transition. Breaking partners = breaking deliveries." },
      { "group": "Operations/Dispatch", "impact": "New complexity in assignment, routing, SLA tracking, and exception handling. Dashboards and reports must be rebuilt for 1:N cardinality." },
      { "group": "Finance/Billing", "impact": "Pricing model must evolve. Per-shipment billing may need to become per-recipient or per-stop. Invoice formats change." },
      { "group": "Customer Support", "impact": "New failure modes to handle: partial deliveries, per-recipient issues. Support tooling must show per-recipient status within a shipment." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is thin on critical details. The 1:N cardinality change is clear, but the spec says nothing about: (1) what 'delivery preferences' actually includes, (2) how shipment-level completion is defined, (3) whether mid-transit modifications are allowed, (4) pricing implications, (5) partner migration strategy, (6) recipient privacy boundaries, (7) maximum recipients per shipment. These are not implementation details — they are business policy decisions that fundamentally alter the domain model's behavior. Without them, acceptance criteria are based on domain expertise and reasonable assumptions, not spec certainty.",
    "high_confidence_areas": [
      "Minimum one recipient invariant",
      "Per-recipient delivery status is required",
      "Backward compatibility for 2M existing records is non-negotiable",
      "Partner APIs must not break",
      "Delivery preferences must be independent per recipient"
    ],
    "low_confidence_areas": [
      "Definition and schema of 'delivery preferences'",
      "Shipment completion semantics (all-delivered vs partial-completion model)",
      "Whether recipients can be added/removed mid-transit",
      "Maximum recipients per shipment",
      "Pricing model implications",
      "Recipient privacy boundaries within a shared shipment",
      "Partner API migration strategy and timeline"
    ],
    "assumptions": [
      "Delivery preferences include at minimum: time window, signature requirement, and safe-place authorization",
      "Shipment completion requires all recipients to reach a terminal state (Delivered or Failed)",
      "A 'Primary Recipient' concept is needed for backward compatibility with partners",
      "Recipient data within a shared shipment is private — Recipient A cannot see Recipient B's details",
      "The migration will be additive (new Recipient table) rather than destructive (modifying existing columns in place)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'delivery preferences' includes. This is not a UI detail — it determines the Recipient entity schema, validation rules, courier workflows, and partner API payloads. Without a concrete definition, the domain model cannot be correctly designed.",
      "affected_stakeholders": ["Senders/Shippers", "Couriers/Drivers", "External Partners", "Engineering"],
      "options": ["A) Minimal: time window + signature required flag", "B) Standard: time window + signature + safe place + contactless + special instructions", "C) Extensible: key-value preference bag with a defined set of known keys"],
      "recommendation": "Option B — it covers known logistics preferences without over-engineering. Define the concrete list with the product team before implementation begins."
    },
    {
      "type": "ambiguity",
      "description": "Shipment completion semantics are undefined. When a Shipment has 3 Recipients and 1 delivery fails permanently, what is the Shipment's terminal status? This affects SLA calculations, billing, partner notifications, and reporting.",
      "affected_stakeholders": ["Operations/Dispatch", "Finance/Billing", "External Partners", "Customer Support"],
      "options": ["A) All-or-nothing: Shipment is 'Failed' if any recipient fails", "B) Partial completion: Shipment is 'Completed with Exceptions' — delivered recipients are billed, failed ones trigger exception flow", "C) Per-recipient only: Shipment has no aggregate status, only recipient-level statuses"],
      "recommendation": "Option B — it reflects physical reality (some goods were delivered) while surfacing exceptions. Option C loses the ability to reason about shipments as a unit."
    },
    {
      "type": "missing_context",
      "description": "No guidance on partner API migration strategy. There are external partners receiving shipment data in the current single-recipient format. The spec does not address: versioning strategy, migration timeline, whether multi-recipient shipments can even be sent to legacy partners, or who is responsible for partner communication.",
      "affected_stakeholders": ["External Partners", "Engineering", "Product"],
      "options": ["A) API versioning with v1 (legacy) and v2 (multi-recipient) running in parallel", "B) Envelope pattern: always send primary recipient in legacy format, add optional 'additional_recipients' array", "C) Per-partner feature flag controlling which format they receive"],
      "recommendation": "Option B for immediate backward compatibility, with Option A as the long-term target. Partners should never receive a format they haven't opted into."
    },
    {
      "type": "ambiguity",
      "description": "Recipient privacy within a multi-recipient Shipment is not addressed. Can Recipient A see that Recipient B exists on the same shipment? Can they see B's address or delivery status? This has legal (GDPR/privacy) and UX implications.",
      "affected_stakeholders": ["Recipients", "Senders/Shippers", "Legal/Compliance"],
      "options": ["A) Full isolation: each recipient sees only their own delivery, unaware of others", "B) Shared visibility: all recipients can see each other (like a group order)", "C) Sender-controlled: sender chooses visibility level per shipment"],
      "recommendation": "Option A as the default — privacy-by-default is safest and avoids regulatory risk. Option C could be a future enhancement."
    }
  ],

  "rejection_reasons": []
}

